Find $x.$

[asy]
unitsize(0.7 cm);

pair A, B, C, D, O;

O = (0,0);
A = 4*dir(160);
B = 5*dir(160 + 180);
C = 8*dir(20);
D = 4*dir(20 + 180);

draw(A--B);
draw(C--D);
draw(A--C);
draw(B--D);

label("$4$", (A + O)/2, SW);
label("$10$", (C + O)/2, SE);
